const MAX_RETRY = 5;   // nombre max de tentatives avant abandon

const loopItem = $('Loop Over Items').all()[0].json;
const id = loopItem.id || 'Q0001';

// ── retryCount lié à l'ITEM, pas à l'historique global du nœud ──
let retryCount = 1;
try {
  const prevRuns = $('Verify Output').all();
  const prev = prevRuns[prevRuns.length - 1].json;
  if (prev && prev.id === id) {
    retryCount = (prev.retryCount || 0) + 1;
  } else {
    retryCount = 1;   // nouvel item → reset
  }
} catch (e) {
  retryCount = 1;
}

let tokenUsage = null;
try {
  const chatRuns = $('Google Gemini Chat Model').all();
  const chatOut = chatRuns[chatRuns.length - 1].json;
  tokenUsage = chatOut.tokenUsage || chatOut.response?.tokenUsage || null;
} catch (e) {
  tokenUsage = null;
}

let output = $json.output || "";
const maxRetriesReached = retryCount > MAX_RETRY;

const isCorrupted =
  output.toLowerCase().includes("calling pinecone") ||
  !output.includes("RECOMMANDED_APIS:");

// ── Si on a épuisé les tentatives ET que la sortie est toujours corrompue,
//    on force une réponse négative propre (exploitable par l'évaluation) ──
if (maxRetriesReached && isCorrupted) {
  output = "Cette fonctionnalité n'existe pas dans le catalogue.\nRECOMMANDED_APIS: []";
}

const shouldRetry = isCorrupted && !maxRetriesReached;

return {
  json: {
    id,
    chatInput: loopItem.chatInput,
    output,
    retryCount,
    maxRetriesReached,
    shouldRetry,
    fallbackApplied: maxRetriesReached && isCorrupted,   // trace pour ton éval
    promptTokens: tokenUsage?.promptTokens ?? null,
    completionTokens: tokenUsage?.completionTokens ?? null,
    totalTokens: tokenUsage?.totalTokens ?? null,
  }
};
